                    let _ =
                        sink.write_blob(&serde_json::to_vec(&denial_payload).unwrap_or_default());
                    sink.emit(&LoopAuditEvent::PolicyDenial {
                        ts: Utc::now(),
                        run_id: cfg.run_id.clone(),
                        session_id: session.id().to_string(),
                        iteration,
